function drawBustUnderlay(canvas,body,hair){let ctx=canvas.getContext('2d'),sw=CHARACTER_IMAGE.naturalWidth/4,sh=CHARACTER_IMAGE.naturalHeight/3,fit=HEAD_FIT[body]||HEAD_FIT[0],w=canvas.width,h=canvas.height,dw=w*fit.scale,dh=h*fit.scale,dx=(w-dw)/2,dy=h*fit.y,cx=w/2;ctx.save();ctx.beginPath();ctx.moveTo(cx-dw*.11,dy+dh*.26);ctx.quadraticCurveTo(cx-dw*.18,dy+dh*.39,cx-dw*.255,dy+dh*.62);ctx.lineTo(cx+dw*.255,dy+dh*.62);ctx.quadraticCurveTo(cx+dw*.18,dy+dh*.39,cx+dw*.11,dy+dh*.26);ctx.closePath();ctx.clip();ctx.drawImage(CHARACTER_IMAGE,body*sw,hair*sh,sw,sh,dx,dy,dw,dh);ctx.restore()}
function drawHeadLayer(canvas,body,hair){let ctx=canvas.getContext('2d'),sw=CHARACTER_IMAGE.naturalWidth/4,sh=CHARACTER_IMAGE.naturalHeight/3,m=HEAD_MASKS[body]||HEAD_MASKS[0],fit=HEAD_FIT[body]||HEAD_FIT[0],w=canvas.width,h=canvas.height,dw=w*fit.scale,dh=h*fit.scale,dx=(w-dw)/2,dy=h*fit.y,cx=dx+dw*m.cx,cy=dy+dh*m.cy,rx=dw*m.rx,ry=dh*m.ry,neck=dy+dh*m.neck;ctx.save();ctx.beginPath();ctx.ellipse(cx,cy,rx,ry,0,0,Math.PI*2);ctx.moveTo(cx-rx*.34,dy+dh*.31);ctx.lineTo(cx+rx*.34,dy+dh*.31);ctx.lineTo(cx+rx*.22,neck);ctx.lineTo(cx-rx*.22,neck);ctx.closePath();ctx.clip();ctx.drawImage(CHARACTER_IMAGE,body*sw,hair*sh,sw,sh,dx,dy,dw,dh);ctx.restore()}
function drawCostume(canvas,body,hair,role){if(!role)return;let paint=()=>{let ctx=canvas.getContext('2d'),sw=COSTUME_IMAGE.naturalWidth/4,sh=COSTUME_IMAGE.naturalHeight/4,fit=COSTUME_FIT[body]||COSTUME_FIT[0],dw=canvas.width*fit.scale,dh=canvas.height*fit.scale,dx=(canvas.width-dw)/2+canvas.width*fit.x,dy=canvas.height*fit.y;ctx.drawImage(COSTUME_IMAGE,body*sw,costumeRow(role)*sh,sw,sh,dx,dy,dw,dh);drawHeadLayer(canvas,body,hair)};if(COSTUME_IMAGE.complete&&COSTUME_IMAGE.naturalWidth)paint();else COSTUME_IMAGE.addEventListener('load',paint,{once:true})}
function drawCharacter(canvas,body,hair,role=null){if(!canvas)return;let draw=()=>{let ctx=canvas.getContext('2d'),sw=CHARACTER_IMAGE.naturalWidth/4,sh=CHARACTER_IMAGE.naturalHeight/3;canvas.width=Math.round(sw);canvas.height=Math.round(sh);ctx.clearRect(0,0,canvas.width,canvas.height);if(role){drawBustUnderlay(canvas,body,hair);drawCostume(canvas,body,hair,role)}else ctx.drawImage(CHARACTER_IMAGE,body*sw,hair*sh,sw,sh,0,0,canvas.width,canvas.height)};if(CHARACTER_IMAGE.complete&&CHARACTER_IMAGE.naturalWidth)draw();else CHARACTER_IMAGE.addEventListener('load',draw,{once:true})}
