function loadMeta(){try{return JSON.parse(localStorage.getItem('packspire_meta_v1'))||{}}catch{return{}}}
function migrateMeta(meta){meta=meta&&typeof meta==='object'?meta:{};meta.stash=(Array.isArray(meta.stash)?meta.stash:[]).filter(x=>typeof x==='string'||x?.templateId).map(normalizeItem);meta.baseGold=Math.max(0,meta.baseGold||0);meta.dungeonsUnlocked=Math.max(1,Math.min(DUNGEONS.length,meta.dungeonsUnlocked||1));meta.dungeonClears=meta.dungeonClears&&typeof meta.dungeonClears==='object'?meta.dungeonClears:{};meta.jobLevels=meta.jobLevels&&typeof meta.jobLevels==='object'?meta.jobLevels:{};meta.currentRole=ROLES[meta.currentRole]?meta.currentRole:null;meta.factions=Object.assign({iron:true,spore:true,guild:true,void:false},meta.factions||{});meta.factionContribution=Object.assign({iron:0,spore:0,guild:0,void:0},meta.factionContribution||{});meta.currentFaction=meta.factions[meta.currentFaction]?meta.currentFaction:'iron';meta.selectedBackpack=BACKPACKS[meta.selectedBackpack]?meta.selectedBackpack:'standard';meta.selectedHeirloomUid=meta.stash.some(item=>item.uid===meta.selectedHeirloomUid)?meta.selectedHeirloomUid:null;meta.discoveredItems=meta.discoveredItems&&typeof meta.discoveredItems==='object'?meta.discoveredItems:{};['sword','shield','ember','herb',...meta.stash.map(item=>item.templateId)].forEach(id=>meta.discoveredItems[id]=true);meta.discoveredEnemies=meta.discoveredEnemies&&typeof meta.discoveredEnemies==='object'?meta.discoveredEnemies:{};meta.character=meta.character&&Number.isInteger(meta.character.body)&&Number.isInteger(meta.character.hair)?{body:Math.max(0,Math.min(3,meta.character.body)),hair:Math.max(0,Math.min(2,meta.character.hair))}:null;meta.vaultLevel=Math.max(0,Math.min(3,meta.vaultLevel??Math.ceil(Math.max(0,meta.stash.length-4)/4)));meta.version=10;return meta}
function vaultCapacity(){return 4+(META.vaultLevel||0)*4}
let META=migrateMeta(loadMeta());META.mastery=META.mastery||{};META.unlocked=META.unlocked||{};META.roles=Object.assign({warrior:true,guardian:true,scout:true,artificer:true},META.roles||{});META.stats=Object.assign({runs:0,wins:0,cards:0,rotations:0,shopBuys:0,events:0,organizes:0},META.stats||{});META.selectedSupplyKit=SUPPLY_KITS[META.selectedSupplyKit]?META.selectedSupplyKit:'blade';META.selectedCarryUids=(Array.isArray(META.selectedCarryUids)?META.selectedCarryUids:[]).filter(uid=>META.stash.some(item=>item.uid===uid)).slice(0,3);META.factionRelationFlags=META.factionRelationFlags&&typeof META.factionRelationFlags==='object'?META.factionRelationFlags:{};if(!META.stash.some(item=>item.uid===META.selectedHeirloomUid&&item.heirloomCertified))META.selectedHeirloomUid=null;META.version=12;
function saveMeta(){try{localStorage.setItem('packspire_meta_v1',JSON.stringify(META))}catch{}}
function unlock(id){if(META.unlocked[id])return;META.unlocked[id]=Date.now();saveMeta();let s=SECRETS.find(x=>x.id===id);if(s)toast(`秘密発見「${s.name}」— ${s.reward}`)}
function isEvolved(id){return !!EVOLUTIONS[id]&&(META.mastery[id]||0)>=EVOLUTIONS[id].need}
function metaMaxHp(){return 42+(META.unlocked.first_win?3:0)+(META.unlocked.eventer?2:0)+(META.unlocked.organizer?2:0)+(META.unlocked.collector?1:0)+(META.unlocked.last_stand?3:0)+(META.unlocked.edge_master?2:0)+(META.unlocked.scarred_relic?2:0)+(META.unlocked.deepest_clear?4:0)}
function metaGold(){return 24+(META.unlocked.three_wins?10:0)+(META.unlocked.merchant?5:0)+(META.unlocked.perfect_weight?3:0)+(META.unlocked.minimalist?7:0)+(META.unlocked.whisper?1:0)+(META.unlocked.rotator?2:0)+(META.unlocked.job_25?5:0)+(META.unlocked.vault_master?5:0)}
function checkMeta(){if(META.stats.cards>=1)unlock('first_card');if((META.mastery.sword||0)>=100)unlock('blade_100');if((META.mastery.dagger||0)>=75)unlock('dagger_75');if((META.mastery.spear||0)>=60)unlock('spear_60');if(META.stats.wins>=1)unlock('first_win');if(META.stats.wins>=3)unlock('three_wins');if(META.stats.rotations>=50)unlock('rotator');if(META.stats.shopBuys>=5)unlock('merchant');if(META.stats.events>=10)unlock('eventer');if(META.stats.organizes>=20)unlock('organizer');if(totalJobLevels()>=25)unlock('job_25');if((META.dungeonClears.hollow_archive||0)>=1){unlock('deepest_clear');unlockFaction('void','虚ろなる大記憶庫を踏破した')}if(META.vaultLevel>=3)unlock('vault_master');if(META.stash.some(item=>item.scars.length>=3))unlock('scarred_relic');saveMeta()}
function unlockRole(id,reason){if(META.roles[id])return;META.roles[id]=true;saveMeta();toast(`隠し役職「${ROLES[id].name}」解禁 — ${reason}`)}
function unlockFaction(id,reason){if(META.factions[id])return;META.factions[id]=true;saveMeta();toast(`新勢力「${factionById(id).name}」解禁 — ${reason}`)}
function jobMax(id){return ROLES[id]?.hidden?15:10}
function jobLevel(id){return Math.max(0,Math.min(jobMax(id),META.jobLevels[id]||0))}
function totalJobLevels(){return Object.keys(ROLES).reduce((n,id)=>n+jobLevel(id),0)}
function factionById(id){return FACTIONS.find(f=>f.id===id)||FACTIONS[0]}
function factionContribution(id){return META.factionContribution[id]||0}
function factionRank(id){let n=factionContribution(id);return n>=50?4:n>=25?3:n>=10?2:1}
function factionRankName(id){let faction=factionById(id);return faction.rankNames[factionRank(id)-1]}
