function factionStandingName(id){let n=factionContribution(id);return n<0?'警戒':n<10?'顔見知り':n<25?'協力者':n<50?'盟友':'象徴'}
function factionEffectText(id,rank=factionRank(id)){return{iron:`防具カードの防御 +${rank}`,spore:`戦闘勝利後のHP回復 +${rank}`,guild:`商店価格 ${rank*5}%引き`,void:`獲得ゴールド +${rank*5}%／呪い装備出現`}[id]}
function checkFactionRelationFlags(){let c=META.factionContribution,flags=META.factionRelationFlags,unlockFlag=(id,text)=>{if(flags[id])return;flags[id]=Date.now();toast(`勢力情勢：${text}`)};if(c.iron>=25&&c.spore<=-10)unlockFlag('iron_spore_war','鉄殻軍と胞子教団の対立が臨界へ近づいた');if(c.iron>=25&&c.guild>=25)unlockFlag('iron_guild_pact','鉄殻軍と荷造り師組合が軍需協定を結んだ');if(c.void>=25&&Math.min(c.iron,c.spore,c.guild)<=-15)unlockFlag('void_eclipse','虚無の影響が既存勢力圏を侵食し始めた')}
function gainJobLevel(id,amount=1){if(!id)return 0;let before=jobLevel(id),room=Math.max(0,100-totalJobLevels()),gain=Math.min(amount,jobMax(id)-before,room);if(gain>0){META.jobLevels[id]=before+gain;saveMeta();checkJobCombinations()}return gain}
function checkJobCombinations(){if(jobLevel('warrior')>=5&&jobLevel('scout')>=5)unlockRole('arsenal_lord','戦士Lv.5と斥候Lv.5を修めた');if(jobLevel('guardian')>=5&&jobLevel('artificer')>=5)unlockRole('pack_saint','守護兵Lv.5と工匠Lv.5を修めた');if(jobLevel('artificer')>=7&&jobLevel('scout')>=3)unlockRole('rune_weaver','工匠Lv.7と斥候Lv.3を修めた');if(['warrior','guardian','scout','artificer'].every(id=>jobLevel(id)>=3))unlockRole('grid_dancer','四基本職をすべてLv.3まで修めた');if(jobLevel('warrior')>=3&&jobLevel('scout')>=3)unlockRole('quickblade','戦士Lv.3と斥候Lv.3を修めた');if(jobLevel('warrior')>=3&&jobLevel('guardian')>=3)unlockRole('anchor_knight','戦士Lv.3と守護兵Lv.3を修めた');if(jobLevel('artificer')>=5&&jobLevel('warrior')>=3)unlockRole('siege_channeler','工匠Lv.5と戦士Lv.3を修めた')}
