function getRotatedLayout(item,rotation=0){let pts=item.shape.map(([x,y],original)=>({x,y,original,attrs:item.cellAttrs?.[original]||{}}));for(let n=0;n<rotation%4;n++)pts=pts.map(p=>({...p,x:-p.y,y:p.x}));let minX=Math.min(...pts.map(p=>p.x)),minY=Math.min(...pts.map(p=>p.y));return pts.map(p=>({...p,x:p.x-minX,y:p.y-minY}))}
function getShape(item,rotation=0){return getRotatedLayout(item,rotation).map(p=>[p.x,p.y])}
function shapeHtml(shape,type){let w=Math.max(...shape.map(p=>p[0]))+1,h=Math.max(...shape.map(p=>p[1]))+1,set=new Set(shape.map(p=>p.join(','))),cells='';for(let y=0;y<h;y++)for(let x=0;x<w;x++)cells+=`<i class="shape-pixel ${set.has(x+','+y)?'on '+type:''}"></i>`;return `<div class="shape-preview" title="${w}×${h} / ${shape.length}マス" style="grid-template-columns:repeat(${w},9px)">${cells}</div>`}
function canPlace(cell,index,rotation,ignoreAnchor=null){let item=defAt(index),shape=getShape(item,rotation),x=cell%6,y=Math.floor(cell/6),occupied=new Set();Object.entries(state.placed).forEach(([a,p])=>{if(a===String(ignoreAnchor))return;getShape(defAt(p.index),p.rotation||0).forEach(o=>occupied.add(+a+o[1]*6+o[0]))});let cells=shape.map(o=>[x+o[0],y+o[1]]);return !cells.some(([a,b])=>a<0||b<0||a>5||b>3||occupied.has(b*6+a))}
function placeAt(cell){if(state.selected===null)return;let rotation=state.rotations[state.selected]||0;if(!canPlace(cell,state.selected,rotation)){message('そこには入りません');return}state.placed[cell]={index:state.selected,rotation};state.selected=null;state.selectedPlaced=String(cell);message('配置しました');renderAll()}
function dropAt(cell){if(!state.drag)return;if(state.drag.kind==='inventory'){state.selected=state.drag.index;placeAt(cell)}else{let old=state.drag.anchor,p=state.placed[old],anchor=cell-state.drag.dy*6-state.drag.dx;if(p&&anchor>=0&&canPlace(anchor,p.index,p.rotation||0,old)){delete state.placed[old];state.placed[anchor]=p;state.selectedPlaced=String(anchor);message('移動しました');renderAll()}else message('そこには移動できません')}state.drag=null}
