function itemCells(anchor,p){return getShape(defAt(p.index),p.rotation||0).map(([x,y])=>({x:(+anchor)%6+x,y:Math.floor((+anchor)/6)+y}))}
function placementMode(anchor,p){let cells=itemCells(anchor,p),center=cells.reduce((n,c)=>n+c.y,0)/cells.length;return center<1?'quick':center>=3?'charge':'stable'}
