function backpackLinks(entries=Object.entries(state.placed)){let links=[];entries.forEach(([a,p],i)=>entries.slice(i+1).forEach(([b,q])=>{if(areAdjacent(a,p,b,q))links.push({a,b,p,q,aId:templateAt(p.index),bId:templateAt(q.index)})}));return links}
