function generateExplorationMap(){let layers=currentDungeon().rooms-1,nodes=[{id:'entrance',layer:0,x:4,y:50,type:'entrance',visited:true,revealed:true}],edges=[],routePool=['event','shop','rest','scavenge','guild'];for(let layer=1;layer<=layers;layer++){let count=layer===layers?2:2+Math.floor(Math.random()*2),ys=count===2?[32,68]:[20,50,80];for(let i=0;i<count;i++)nodes.push({id:`n${layer}-${i}`,layer,x:4+layer*(92/layers),y:ys[i],type:layer===layers&&i===0?'guild':routePool[Math.floor(Math.random()*routePool.length)],visited:false,revealed:false});let prev=nodes.filter(n=>n.layer===layer-1),now=nodes.filter(n=>n.layer===layer);prev.forEach((from,i)=>{edges.push({from:from.id,to:now[i%now.length].id,hazard:Math.random()<.38?shuffle(Object.keys(PATH_HAZARDS))[0]:null});if(now.length>1&&Math.random()<.72)edges.push({from:from.id,to:now[(i+1)%now.length].id,hazard:Math.random()<.28?shuffle(Object.keys(PATH_HAZARDS))[0]:null})});if(layer>1&&Math.random()<.7){let from=prev[Math.floor(Math.random()*prev.length)],to=now[Math.floor(Math.random()*now.length)],conditions=['scout','artificer','void','heirloom'];if(!edges.some(e=>e.from===from.id&&e.to===to.id&&e.secret))edges.push({from:from.id,to:to.id,secret:true,condition:conditions[Math.floor(Math.random()*conditions.length)],hazard:null})}}return{nodes,edges,current:'entrance',scoutedFrom:[]}}
const generateExplorationMapCore=generateExplorationMap;
generateExplorationMap=function(){let map=generateExplorationMapCore(),layers=currentDungeon().rooms-1;map.nodes.forEach(node=>node.x=9+node.layer*(82/layers));map.nodes.filter(node=>node.layer>0).forEach((node,index)=>{if(!map.edges.some(edge=>edge.to===node.id&&!edge.secret)){let previous=map.nodes.filter(other=>other.layer===node.layer-1),from=previous[index%previous.length];map.edges.push({from:from.id,to:node.id,hazard:null})}});return map}
function generateOpenSpireMap(){let nodes=[],edges=[],types=['empty','empty','empty','event','rest','scavenge','guild','treasure'];for(let row=0;row<6;row++)for(let col=0;col<6;col++)nodes.push({id:`o${row}-${col}`,row,col,x:8+col*16.8,y:9+row*16.4,type:types[Math.floor(Math.random()*types.length)],visited:false,revealed:false,cleared:false});let entrance=nodes.find(n=>n.id==='o2-0'),boss=nodes.find(n=>n.id==='o3-5');entrance.type='entrance';entrance.visited=true;entrance.revealed=true;boss.type='boss';for(let row=0;row<6;row++)for(let col=0;col<5;col++)edges.push({a:`o${row}-${col}`,b:`o${row}-${col+1}`});for(let row=0;row<5;row++){let guaranteed=[Math.floor(Math.random()*6),Math.floor(Math.random()*6)];for(let col=0;col<6;col++)if(guaranteed.includes(col)||Math.random()<.22)edges.push({a:`o${row}-${col}`,b:`o${row+1}-${col}`})}let usable=nodes.filter(n=>!['entrance','boss'].includes(n.type)),enemies=shuffle([...usable]).slice(0,8+(state.mapFragment==='blood'?1:0)).map((node,index)=>({id:`enemy-${index}`,node:node.id,elite:index<2+(state.mapFragment==='blood'?1:0),alive:true})),merchantCandidates=usable.filter(n=>!enemies.some(e=>e.node===n.id)),merchantNode=merchantCandidates[Math.floor(Math.random()*merchantCandidates.length)]?.id;if(state.mapFragment==='treasure')shuffle(usable.filter(n=>n.type==='empty')).slice(0,2).forEach(n=>n.type='treasure');if(state.mapFragment==='shortcut')edges.push({a:entrance.id,b:'o2-3',secret:true,label:'地図断片の橋'});return{mode:'open',nodes,edges,current:entrance.id,entrance:entrance.id,boss:boss.id,enemies,merchantNode,fragment:state.mapFragment,steps:0,scoutedFrom:[],secured:[],brokenPaths:[],mapStarted:false}}
const generateOpenSpireMapBase=generateOpenSpireMap;
generateOpenSpireMap=function(){let map=generateOpenSpireMapBase(),dungeon=currentDungeon(),target=(dungeon.mapEnemies||8)+(state.mapFragment==='blood'?1:0),eliteTarget=(dungeon.mapElites||2)+(state.mapFragment==='blood'?1:0),occupied=new Set(map.enemies.map(enemy=>enemy.node));if(map.enemies.length<target){let candidates=shuffle(map.nodes.filter(node=>!['entrance','boss'].includes(node.type)&&!occupied.has(node.id)&&node.id!==map.merchantNode));while(map.enemies.length<target&&candidates.length){let node=candidates.pop();map.enemies.push({id:`enemy-${map.enemies.length}`,node:node.id,elite:false,alive:true})}}map.enemies.forEach((enemy,index)=>enemy.elite=index<eliteTarget);map.dungeon=dungeon.id;return map}
function openNeighbors(id){let map=state.map;return map.edges.filter(edge=>edge.a===id||edge.b===id).map(edge=>edge.a===id?edge.b:edge.a)}
function openDistance(a,b){let na=state.map.nodes.find(n=>n.id===a),nb=state.map.nodes.find(n=>n.id===b);return Math.abs(na.row-nb.row)+Math.abs(na.col-nb.col)}
function alertStage(){return state.alertSteps>=9?'封鎖':state.alertSteps>=4?'警戒':'静穏'}
function revealOpenArea(center,radius=1){state.map.nodes.filter(node=>openDistance(center,node.id)<=radius).forEach(node=>node.revealed=true)}
function moveOpenEntities(){let map=state.map,chance=alertStage()==='封鎖'?.72:alertStage()==='警戒'?.5:.3;map.enemies.filter(enemy=>enemy.alive).forEach(enemy=>{if(Math.random()>chance)return;let choices=openNeighbors(enemy.node).filter(id=>id!==map.boss&&id!==map.entrance);if(choices.length)enemy.node=choices[Math.floor(Math.random()*choices.length)]});if(map.merchantNode&&map.steps%2===0){let choices=openNeighbors(map.merchantNode).filter(id=>id!==map.boss);if(choices.length)map.merchantNode=choices[Math.floor(Math.random()*choices.length)]}}
function openRouteName(node){let route=ROUTES[node.type],names={empty:['·','静かな通路','特別な気配はない'],treasure:['✦','宝物区画','未回収の装備反応'],boss:['☠','荷喰らいの玉座','古塔最深部'],entrance:['●','古塔入口','ここから途中帰還できる']};return route?[route.icon,route.name,route.desc]:(names[node.type]||['◇','未知の区画','詳細不明'])}
function showOpenSpireMap(){let map=state.map,current=map.nodes.find(n=>n.id===map.current);$('#mapPath').classList.add('open-world-map');revealOpenArea(map.current,jobLevel('scout')>=3?2:1);if(map.fragment==='merchant'&&map.merchantNode)map.nodes.find(n=>n.id===map.merchantNode).revealed=true;$('#mapNodes').innerHTML=map.nodes.map(node=>{let known=node.revealed||node.visited,reachable=openNeighbors(map.current).includes(node.id),info=openRouteName(node),enemy=map.enemies.find(e=>e.alive&&e.node===node.id),merchant=map.merchantNode===node.id,isCurrent=node.id===map.current,occupant=known&&enemy?enemy.elite?' ◆精鋭':' ⚔敵':known&&merchant?' ♜商人':'';return `<button class="map-node open-node ${isCurrent?'current':''} ${node.visited?'visited':''} ${reachable?'reachable':''} ${known?'known':'unknown'}" data-open-node="${node.id}" style="--map-x:${node.x}%;--map-y:${node.y}%" ${reachable?'':'disabled'}><span class="node-icon">${known?info[0]:'？'}</span><b>${known?info[1]:'未踏区画'}${occupant}</b><small>${isCurrent?'現在地':known?info[2]:'情報なし'}</small></button>`}).join('');$('#mapEdges').setAttribute('viewBox','0 0 100 100');$('#mapEdges').innerHTML=map.edges.map(edge=>{let a=map.nodes.find(n=>n.id===edge.a),b=map.nodes.find(n=>n.id===edge.b),known=a.revealed||b.revealed||a.visited||b.visited,active=edge.a===map.current||edge.b===map.current;return `<line x1="${a.x}" y1="${a.y}" x2="${b.x}" y2="${b.y}" class="${active?'active':''} ${edge.secret?'secret':''} ${known?'':'unseen'}"/>`}).join('');let alive=map.enemies.filter(e=>e.alive).length;$('#mapIntel').textContent=`36区画／移動${map.steps}回／警戒：${alertStage()}／活動中の敵 ${alive}体／戦闘勝利 ${state.battlesWon}回`;$('#scoutMap').disabled=map.scoutedFrom.includes(map.current);$('#scoutMap').textContent=map.scoutedFrom.includes(map.current)?'偵察済み':'周辺を偵察';$('#extractDungeon').classList.toggle('hidden',map.current!==map.entrance||!map.mapStarted);renderOpenMapActions();document.querySelectorAll('[data-open-node].reachable').forEach(button=>button.onclick=()=>travelOpenSpire(button.dataset.openNode))}
function travelOpenSpire(id){let map=state.map;if(!openNeighbors(map.current).includes(id))return;map.current=id;map.steps++;map.mapStarted=true;state.alertSteps++;let node=map.nodes.find(n=>n.id===id);node.visited=true;node.revealed=true;moveOpenEntities();resolveOpenSpireNode(node)}
function resolveOpenSpireNode(node){let map=state.map,enemy=map.enemies.find(e=>e.alive&&e.node===node.id);if(node.type==='boss'){prepareOpenBattle(node,true,null);return}if(enemy){prepareOpenBattle(node,false,enemy);return}if(map.merchantNode===node.id){openShop();return}if(node.cleared){showMap();return}if(node.type==='treasure'){node.cleared=true;let pool=Object.keys(ITEMS).filter(id=>!hasTemplate(id)&&id!=='cursed_blade'),id=pool[Math.floor(Math.random()*pool.length)];if(id){discoverItem(id);state.inventory.push(makeItem(id));toast(`${ITEMS[id].name}を発見した`)}showMap();return}if(node.type==='empty'||node.type==='entrance'){showMap();return}node.cleared=true;enterRoute(node.type)}
function prepareOpenBattle(node,boss,enemy){state.pendingBattle=true;state.pendingBoss=boss;state.battleNode=node.id;state.battleEnemyId=enemy?.id||null;state.floor=boss?currentDungeon().rooms:Math.min(currentDungeon().rooms-1,1+state.battlesWon+(enemy?.elite?2:0));show('prepScreen');renderAll();message(boss?'ボス戦へ向けて荷造りしてください':enemy?.elite?'精鋭との戦闘準備':'敵影を確認。戦闘準備をしてください')}
function renderOpenMapActions(){let actions=[];if(jobLevel('warrior')>=1&&!state.map.brokenPaths.includes(state.map.current))actions.push(`<button data-map-action="break">⚔ 壁を破壊して新しい道を作る（警戒+2）</button>`);if(jobLevel('guardian')>=1&&!state.map.secured.includes(state.map.current))actions.push(`<button data-map-action="secure">⬟ 区画を確保して警戒を下げる</button>`);if(jobLevel('artificer')>=1&&state.map.current!==state.map.entrance&&!state.map.edges.some(e=>e.secret&&e.a===state.map.current&&e.b===state.map.entrance))actions.push(`<button data-map-action="bridge">⚙ 入口への昇降路を修復する</button>`);$('#mapActions').innerHTML=actions.join('');document.querySelectorAll('[data-map-action]').forEach(button=>button.onclick=()=>useOpenMapAction(button.dataset.mapAction))}
function useOpenMapAction(action){let map=state.map;if(action==='break'){let current=map.nodes.find(n=>n.id===map.current),choices=map.nodes.filter(n=>openDistance(map.current,n.id)<=3&&n.id!==map.current&&!openNeighbors(map.current).includes(n.id));if(choices.length){let target=choices[Math.floor(Math.random()*choices.length)];map.edges.push({a:map.current,b:target.id,secret:true,label:'破壊した壁'});map.brokenPaths.push(map.current);state.alertSteps+=2;toast('壁を破壊し、新しい道を開いた')}}if(action==='secure'){map.secured.push(map.current);state.alertSteps=Math.max(0,state.alertSteps-3);toast('区画を確保し、警戒を下げた')}if(action==='bridge'){map.edges.push({a:map.current,b:map.entrance,secret:true,label:'修復した昇降路'});toast('入口へ戻る昇降路を修復した')}showMap()}
function secretPathOpen(edge){if(!edge.secret)return true;if(edge.condition==='scout')return jobLevel('scout')>=3||jobLevel('hunter')>=1;if(edge.condition==='artificer')return jobLevel('artificer')>=3||state.inventory.some(item=>item.templateId==='bomb');if(edge.condition==='void')return state.faction.id==='void'||jobLevel('void_apostle')>=1;if(edge.condition==='heirloom')return !!state.heirloomUid;return false}
function secretPathLabel(edge){return{scout:'斥候が見つけた獣道',artificer:'工匠が開いた保守路',void:'虚無にだけ映る亀裂',heirloom:'家宝が示した古道'}[edge.condition]||'隠し道'}
function nodeIntelKnown(node){let current=state.map.nodes.find(n=>n.id===state.map.current),near=node.layer<=current.layer+1,scouted=state.map.scoutedFrom.includes(state.map.current);return node.visited||scouted&&near||jobLevel('scout')>=1&&near||state.faction.id==='guild'&&node.type==='shop'||jobLevel('artificer')>=1&&['guild','scavenge'].includes(node.type)}
function visibleMapEdges(){return state.map.edges.filter(edge=>secretPathOpen(edge))}
function showMap(){if(!state.map)state.map=generateExplorationMap();show('mapScreen');let map=state.map,current=map.nodes.find(n=>n.id===map.current),edges=visibleMapEdges(),scouted=map.scoutedFrom.includes(map.current),vision=jobLevel('scout')>=3?2:1,visibleNodes=new Set(map.nodes.filter(node=>node.layer<=current.layer+vision||node.visited).map(node=>node.id));edges.filter(edge=>edge.from===map.current).forEach(edge=>visibleNodes.add(edge.to));let rendered=map.nodes.filter(node=>visibleNodes.has(node.id));$('#mapNodes').innerHTML=rendered.map(node=>{let route=ROUTES[node.type]||{icon:'●',name:'入口',desc:'遠征開始地点'},known=node.type==='entrance'||nodeIntelKnown(node),reachable=edges.some(edge=>edge.from===map.current&&edge.to===node.id),isCurrent=node.id===map.current;return `<button class="map-node ${isCurrent?'current':''} ${node.visited?'visited':''} ${reachable?'reachable':''} ${known?'known':'unknown'}" data-node="${node.id}" style="--map-x:${node.x}%;--map-y:${node.y}%" ${reachable?'':'disabled'}><span class="node-icon">${known?route.icon:'？'}</span><b>${known?route.name:'未確認区画'}</b><small>${isCurrent?'現在地':known?route.desc:'近づくか偵察すると判明'}</small></button>`}).join('');$('#mapEdges').setAttribute('viewBox','0 0 100 100');$('#mapEdges').innerHTML=edges.filter(edge=>visibleNodes.has(edge.from)&&visibleNodes.has(edge.to)).map(edge=>{let a=map.nodes.find(n=>n.id===edge.from),b=map.nodes.find(n=>n.id===edge.to),active=edge.from===map.current,secret=edge.secret;return `<line x1="${a.x}" y1="${a.y}" x2="${b.x}" y2="${b.y}" class="${active?'active':''} ${secret?'secret':''}"/>`}).join('');let exits=edges.filter(edge=>edge.from===map.current),hazards=scouted?exits.map(edge=>edge.secret?secretPathLabel(edge):edge.hazard?PATH_HAZARDS[edge.hazard].name:'安全そうな道').join('／'):'未調査';$('#mapIntel').textContent=`第${state.floor}/${currentDungeon().rooms}戦後　接続 ${exits.length}本　道の情報：${hazards}`;$('#scoutMap').disabled=scouted;$('#scoutMap').textContent=scouted?'偵察済み':'周辺を偵察';document.querySelectorAll('.map-node.reachable').forEach(button=>button.onclick=()=>travelToNode(button.dataset.node))}
const showLayeredMap=showMap;
showMap=function(){if(state.openWorld&&state.map?.mode==='open'){show('mapScreen');showOpenSpireMap();return}$('#mapPath').classList.remove('open-world-map');$('#extractDungeon').classList.add('hidden');$('#mapActions').innerHTML='';showLayeredMap()}
function travelToNode(id){let map=state.map,edge=visibleMapEdges().find(path=>path.from===map.current&&path.to===id);if(!edge)return;let node=map.nodes.find(n=>n.id===id);applyPathHazard(edge);map.current=id;node.visited=true;node.revealed=true;state.scoutUsed=false;enterRoute(node.type)}
function applyPathHazard(edge){if(!edge.hazard)return;if(edge.hazard==='dark'&&jobLevel('scout')<1){state.hp=Math.max(1,state.hp-2);toast('暗闇で足を取られ、2ダメージ')}if(edge.hazard==='rubble'&&jobLevel('artificer')<1&&!state.inventory.some(item=>item.templateId==='bomb')){state.inventory.forEach(item=>item.durability=Math.max(0,item.durability-1));toast('崩落路で全装備の耐久が1低下')}if(edge.hazard==='patrol'&&state.faction.id!=='iron'){state.pathEnemyBonus=(state.pathEnemyBonus||0)+1;toast('巡回隊に発見された。次の敵の攻撃+1')}}
function enterRoute(type){if(type==='guild'){openGuild();return}if(type==='shop'){openShop();return}if(type==='rest'){let heal=Math.min(12,state.maxHp-state.hp);state.hp+=heal;repairAllItems();toast(`${heal} HP回復し、全装備を修理した`);continueRun();return}if(type==='scavenge'){state.hp=Math.max(1,state.hp-6);state.gold+=24;toast('6 HPを失い、24Gを発見した');continueRun();return}openEvent()}
function changeRoleAtShrine(id){if(!META.roles[id]||id===state.role)return;let old=ROLES[state.role],next=ROLES[id];state.maxHp=Math.max(1,state.maxHp-(old.hp||0)+(next.hp||0));state.hp=Math.min(state.hp,state.maxHp);state.role=id;META.currentRole=id;if(jobLevel(id)===0)gainJobLevel(id);saveMeta();toast(`${next.name}へ転職した`);continueRun()}
function showRoleChangeChoices(){let roles=Object.keys(ROLES).filter(id=>META.roles[id]&&id!==state.role);$('#eventText').textContent='ここでのみ現在の役職を変更できる。習得済みレベルはすべて残る。';$('#eventChoices').innerHTML=roles.map(id=>`<button class="event-choice role-change" data-role="${id}">${ROLES[id].icon} ${ROLES[id].name} Lv.${jobLevel(id)}</button>`).join('')+'<button class="event-choice" id="cancelRoleChange">戻る</button>';document.querySelectorAll('.role-change').forEach(button=>button.onclick=()=>changeRoleAtShrine(button.dataset.role));$('#cancelRoleChange').onclick=openGuild}
function openGuild(){show('eventScreen');$('#eventIcon').textContent='♝';$('#eventTitle').textContent='継職の祭壇';let next=PROMOTIONS[state.role],level=jobLevel(state.role),canPromote=next&&level>=5&&!META.roles[next];$('#eventText').textContent=canPromote?`${ROLES[state.role].name} Lv.${level}の経験が、上級職への道を開いている。`:'役職の変更、または現在の役職の修練を行える。';$('#eventChoices').innerHTML=`${canPromote?`<button class="event-choice" id="promoteRole">${ROLES[next].icon} ${ROLES[next].name}を解禁</button>`:''}<button class="event-choice" id="changeRole">役職を変更する</button><button class="event-choice" id="trainRole">${ROLES[state.role].name}を修練する</button>`;if(canPromote)$('#promoteRole').onclick=()=>{META.roles[next]=true;gainJobLevel(next);saveMeta();toast(`上級職「${ROLES[next].name}」を解禁した`);openGuild()};$('#changeRole').onclick=showRoleChangeChoices;$('#trainRole').onclick=()=>{let gain=gainJobLevel(state.role);toast(gain?'役職レベルが1上がった':'合計または役職レベルが上限に達している');continueRun()}}
const EVENTS=[
 {icon:'☽',title:'囁く井戸',text:'底から「重いものを寄越せ」と声が響く。',choices:[{label:'10Gを投げる',effect:()=>{if(state.gold<10)return false;state.gold-=10;state.maxHp+=5;state.hp+=5;toast('最大HP +5') }},{label:'立ち去る',effect:()=>toast('何も起こらなかった')}]},
 {icon:'⚙',title:'壊れた昇降機',text:'危険な近道と、遠回りの階段がある。',choices:[{label:'昇降機を使う（50%）',effect:()=>{if(Math.random()<.5){state.gold+=30;toast('30Gを発見した')}else{state.hp=Math.max(1,state.hp-9);toast('落下して9ダメージ')}}},{label:'階段を使う（HP+4）',effect:()=>{state.hp=Math.min(state.maxHp,state.hp+4);toast('慎重に進み4HP回復')}}]},
 {icon:'✦',title:'荷造り師の亡霊',text:'亡霊は装備の傷を見つめ、手を差し出した。',choices:[{label:'8Gで全装備を修理',effect:()=>{if(state.gold<8)return false;state.gold-=8;repairAllItems();toast('全装備の耐久度が回復した')}},{label:'断る',effect:()=>toast('亡霊は消えた')}]},
 {icon:'♞',title:'ライバル探索者',text:'同じ戦利品を狙う探索者が道を塞いだ。',choices:[{label:'決闘する（HP-5、35G）',effect:()=>{state.hp=Math.max(1,state.hp-5);state.gold+=35;toast('ライバルを退けた')}},{label:'物資を交換する（15G）',effect:()=>{if(state.gold<15)return false;state.gold-=15;repairAllItems();toast('装備を修理してもらった')}}]},
 {icon:'⌘',title:'灰印の保険屋',text:'「どれか一つなら、塔の外まで必ず回収してみせよう」',choices:[{label:'12Gで未保険の装備1個に保険',effect:()=>{if(state.gold<12)return false;let pool=state.inventory.filter(item=>!item.insured&&item.uid!==state.heirloomUid);if(!pool.length){toast('保険を付けられる装備がない');return}state.gold-=12;let item=pool[Math.floor(Math.random()*pool.length)];item.insured=true;toast(`${ITEMS[item.templateId].name}に保険タグが付いた`)}},{label:'立ち去る',effect:()=>toast('契約を見送った')}]},
 {icon:'◉',title:'名を失った巡礼者',text:'紫の外套をまとった者が、存在しない道への同行を求めている。',choices:[{label:'最大HPを3捧げ、虚無の巡礼者を発見',effect:()=>{if(META.factions.void){toast('虚無の巡礼者はすでに発見済み');return}state.maxHp=Math.max(12,state.maxHp-3);state.hp=Math.min(state.hp,state.maxHp);unlockFaction('void','名を失った巡礼者と契約した')}},{label:'目を合わせず立ち去る',effect:()=>toast('巡礼者は闇へ消えた')}]}];
function openEvent(){show('eventScreen');let e=EVENTS[Math.floor(Math.random()*EVENTS.length)];$('#eventIcon').textContent=e.icon;$('#eventTitle').textContent=e.title;$('#eventText').textContent=e.text;$('#eventChoices').innerHTML=e.choices.map((c,i)=>`<button class="event-choice" data-i="${i}">${c.label}</button>`).join('');document.querySelectorAll('.event-choice').forEach(b=>b.onclick=()=>{let ok=e.choices[+b.dataset.i].effect();if(ok===false){toast('ゴールドが足りない');return}META.stats.events++;checkMeta();continueRun()})}
function checkCollector(){if(state.inventory.length>=10)unlock('collector');if(['sword','dagger','spear'].every(hasTemplate))unlockRole('arsenal_lord','剣・短剣・槍を一度に集めた')}
function checkRoleUnlocks(){let entries=Object.entries(state.placed),ids=entries.map(([,p])=>templateAt(p.index));if(['shield','plate','buckler'].every(id=>ids.includes(id)))unlockRole('pack_saint','三種の防具を同時に配置した');let runes=entries.filter(([,p])=>['ember','crystal'].includes(templateAt(p.index)));if(runes.length===2){let corners=[[0,0],[5,3],[5,0],[0,3]],hits=runes.map(([a,p])=>itemCells(a,p).filter(c=>corners.some(k=>k[0]===c.x&&k[1]===c.y)));if(hits[0].some(a=>hits[1].some(b=>a.x+b.x===5&&a.y+b.y===3)))unlockRole('rune_weaver','二つのルーンで対角線を結んだ')}let byAnchor=new Map(entries.map(([a,p])=>[+a,defAt(p.index).type]));for(let y=0;y<3;y++)for(let x=0;x<5;x++){let q=y*6+x,square=[q,q+1,q+6,q+7];if(square.every(n=>byAnchor.has(n))&&new Set(square.map(n=>byAnchor.get(n))).size===4)unlockRole('grid_dancer','異種装備の基点で2×2の正方形を作った')}let weapons=entries.filter(([,p])=>defAt(p.index).type==='weapon');if(weapons.length===1&&['sword','dagger'].includes(templateAt(weapons[0][1].index))&&itemCells(weapons[0][0],weapons[0][1]).every(c=>c.x>=4))unlockRole('right_hand_swordsman','右2列に片手武器だけを構えた')}
function openShop(){show('shopScreen');let ids=shuffle(Object.keys(ITEMS).filter(id=>!hasTemplate(id)&&id!=='cursed_blade')).slice(0,3),factionDiscount=state.faction.id==='guild'?1-factionRank('guild')*.05:1,discount=(BACKPACKS[state.backpack].shop||1)*factionDiscount;$('#shopItems').innerHTML=ids.map(id=>{let x=ITEMS[id],price=Math.round((14+x.shape.length*4)*discount);return `<button type="button" class="reward shop-item" data-id="${id}" data-price="${price}"><div class="big-icon art-reward" style="--item-x:${ITEM_ART[id][0]/3*100}%;--item-y:${ITEM_ART[id][1]/2*100}%"></div><h3>${x.name}</h3><p>${x.rule}<br>${x.shape.length}マス</p><b>${price}G</b></button>`}).join('')||'<p>売り切れだ。</p>';document.querySelectorAll('.shop-item').forEach(el=>el.addEventListener('click',()=>{if(el.disabled)return;let id=el.dataset.id,price=Number(el.dataset.price),before=state.gold;if(!Number.isFinite(price)||price<0){toast('価格データが不正です');return}if(before<price){toast('ゴールドが足りない');return}el.disabled=true;state.gold=before-price;$('#gold').textContent=String(state.gold);state.inventory.push(makeItem(id));META.stats.shopBuys++;checkMeta();checkCollector();el.remove();toast(`${ITEMS[id].name}を${price}Gで購入（${before}G → ${state.gold}G）`)},{once:true}));$('#leaveShop').onclick=continueRun}
function continueRun(){if(state.openWorld&&!state.pendingBattle){showMap();return}show('prepScreen');renderAll()}
function toast(text){let el=$('#toast');el.textContent=text;el.classList.add('show');clearTimeout(toast.timer);toast.timer=setTimeout(()=>el.classList.remove('show'),1800)}
function pulse(selector,cls){let el=$(selector);el.classList.remove(cls);void el.offsetWidth;el.classList.add(cls);setTimeout(()=>el.classList.remove(cls),300)}
function safeProtectedUids(){let safe=new Set(BACKPACKS[state.backpack].safe||[]),uids=new Set;state.inventory.filter(item=>item.insured).forEach(item=>uids.add(item.uid));Object.entries(state.placed).forEach(([anchor,p])=>{let cells=itemCells(anchor,p).map(c=>c.y*6+c.x);if(cells.length&&cells.every(cell=>safe.has(cell)))uids.add(itemAt(p.index).uid)});return uids}
function returnItems(items,failed){let stored=0;items.filter(item=>item.origin!=='supply').forEach(item=>{let saved=normalizeItem(item);saved.heirloom=false;saved.insured=false;saved.origin='vault';if(failed&&saved.scars.length<3){let available=Object.keys(SCAR_TYPES).filter(type=>!saved.scars.some(s=>s.type===type)),type=available[Math.floor(Math.random()*available.length)];if(type)saved.scars=[...saved.scars,{type,floor:state.floor,dungeon:state.dungeon,at:Date.now()}]}let i=META.stash.findIndex(old=>old.uid===saved.uid);if(i>=0){META.stash[i]=saved;stored++}else if(META.stash.length<vaultCapacity()){META.stash.push(saved);stored++}});checkMeta();return stored}
let pendingEnd=null,recoverySelected=[];
function endGame(win){let dungeon=currentDungeon(),dungeonIndex=DUNGEONS.findIndex(d=>d.id===dungeon.id),unlocked=false;if(win){META.stats.wins++;META.dungeonClears[dungeon.id]=(META.dungeonClears[dungeon.id]||0)+1;if(META.dungeonsUnlocked===dungeonIndex+1&&META.dungeonsUnlocked<DUNGEONS.length){META.dungeonsUnlocked++;unlocked=true}if(Object.keys(state.placed).length<=2)unlock('minimalist');if(state.hp===1)unlock('last_stand');checkMeta()}let safe=safeProtectedUids(),eligible=state.inventory.filter(item=>item.origin!=='supply'),mandatory=eligible.filter(item=>item.origin==='heirloom'||safe.has(item.uid)||win&&item.origin==='vault'),optional=win?eligible.filter(item=>item.origin==='loot'&&!safe.has(item.uid)):[],recovered=win?state.gold:Math.floor(state.gold*.25);pendingEnd={win,dungeon,unlocked,recovered,mandatory};if(win&&optional.length){recoverySelected=[];$('#recoveryChoices').innerHTML=optional.map(item=>`<button class="recovery-choice" data-uid="${item.uid}"><b>${ITEMS[item.templateId].icon} ${ITEMS[item.templateId].name}</b><small>${ITEMS[item.templateId].rule}</small></button>`).join('');document.querySelectorAll('.recovery-choice').forEach(button=>button.onclick=()=>{let uid=button.dataset.uid;if(recoverySelected.includes(uid))recoverySelected=recoverySelected.filter(x=>x!==uid);else if(recoverySelected.length<2)recoverySelected.push(uid);else{toast('追加戦果は2個まで');return}button.classList.toggle('selected',recoverySelected.includes(uid));$('#recoveryCapacity').textContent=`追加戦果 ${recoverySelected.length} / 2　保管庫空き ${Math.max(0,vaultCapacity()-META.stash.length)}枠`});$('#recoveryCapacity').textContent=`追加戦果 0 / 2　保管庫空き ${Math.max(0,vaultCapacity()-META.stash.length)}枠`;show('recoveryScreen');return}finishEndGame([])}
function finishEndGame(selected){if(!pendingEnd)return;let {win,dungeon,unlocked,recovered,mandatory}=pendingEnd,chosen=state.inventory.filter(item=>selected.includes(item.uid)),stored=returnItems([...mandatory,...chosen],!win);META.baseGold+=recovered;META.selectedCarryUids=(state.departingCarryUids||[]).filter(uid=>META.stash.some(item=>item.uid===uid));if(!META.stash.some(item=>item.uid===META.selectedHeirloomUid))META.selectedHeirloomUid=null;saveMeta();show('gameOver');$('#endTitle').textContent=win?`${dungeon.name} 踏破成功！`:'探索終了';$('#endText').textContent=win?`${recovered}Gを持ち帰り、家宝・持込品・安全戦果を含む${stored}個を保管した。${unlocked?'次のダンジョンが解禁された。':''}`:`${dungeon.name} 第${state.floor}階層で力尽きた。${recovered}Gと保護された装備${stored}個を回収した。安全マス外の持込品は失われた。`;pendingEnd=null}
function renderMeta(){let found=SECRETS.filter(s=>META.unlocked[s.id]).length;$('#metaRuns').textContent=META.stats.runs;$('#metaWins').textContent=META.stats.wins;$('#secretCount').textContent=`${found} / ${SECRETS.length}`;$('#masteryList').innerHTML=Object.entries(EVOLUTIONS).map(([id,e])=>{let n=META.mastery[id]||0,done=n>=e.need;return `<div class="mastery-entry"><div class="mastery-head"><b class="${done?'evolved':''}">${done?'★ '+e.name:ITEMS[id].baseName||ITEMS[id].name}</b><span>${Math.min(n,e.need)} / ${e.need}</span></div><div class="mastery-bar"><i style="width:${Math.min(100,n/e.need*100)}%"></i></div><small>${done?e.bonus:'使用するたび記憶が蓄積される'}</small></div>`}).join('');$('#secretList').innerHTML=SECRETS.map(s=>{let open=META.unlocked[s.id];return `<div class="secret-entry ${open?'unlocked':'locked'}"><b>${open?'✦ '+s.name:'◆ ？？？？？？'}</b><small>${open?s.hint+' / '+s.reward:'条件も報酬も隠されている'}</small></div>`}).join('');$('#roleArchive').innerHTML=Object.entries(ROLES).filter(([id])=>META.roles[id]).map(([,r])=>`<span class="role-chip ${r.advanced?'advanced':''} ${r.hidden?'hidden-role':''}">${r.icon} ${r.name}</span>`).join('');$('#rumorList').innerHTML=RUMORS.map(([name,text,need])=>`<div class="rumor"><b>${META.stats.cards>=need?name:'？？？'}</b><br>${META.stats.cards>=need?text:`あと${need-META.stats.cards}回カードを使えば噂が聞こえる`}</div>`).join('')}
$('#openMeta').onclick=()=>{let current=document.querySelector('.screen:not(.hidden)');state.metaReturn=current?current.id:'prepScreen';renderMeta();show('metaScreen')};
$('#closeMeta').onclick=()=>show(state.metaReturn||'prepScreen');
let titleClicks=0;document.querySelector('h1').onclick=()=>{titleClicks++;if(titleClicks===7){unlock('whisper');document.querySelector('h1').textContent='PACK REMEMBERS';setTimeout(()=>document.querySelector('h1').innerHTML='PACK<span>SPIRE</span>',1400)}};
$('#newExpedition').onclick=reset;
$('#openLoadoutHub').onclick=renderVaultHub;
$('#openStatusHub').onclick=renderStatus;
$('#openCompendiumHub').onclick=()=>renderCompendium('roles');
document.querySelectorAll('#compendiumTabs button').forEach(button=>button.onclick=()=>renderCompendium(button.dataset.tab));
document.addEventListener('click',event=>{let item=event.target.closest?.('.shop-item');if(item&&state&&state.gold>=Number(item.dataset.price))discoverItem(item.dataset.id)},true);
$('#confirmCharacter').onclick=()=>{META.character={...characterDraft};saveMeta();enterHub();toast('探索者の姿を記憶した')};
$('#openFacilities').onclick=()=>$('#facilityModal').classList.remove('hidden');
$('#closeFacilities').onclick=()=>$('#facilityModal').classList.add('hidden');
$('#facilityModal').onclick=event=>{if(event.target.id==='facilityModal')event.currentTarget.classList.add('hidden')};
$('#openForge').onclick=()=>{$('#facilityModal').classList.add('hidden');renderForge()};
$('#openFaction').onclick=()=>{$('#facilityModal').classList.add('hidden');renderFactionFacility()};
$('#upgradeHubVault').onclick=()=>{if(META.vaultLevel>=3)return;let cost=50*(META.vaultLevel+1);if(META.baseGold<cost){toast('拠点の保管金が足りない');return}META.baseGold-=cost;META.vaultLevel++;saveMeta();renderVaultHub();toast(`保管庫を${vaultCapacity()}枠へ拡張した`)};
document.querySelectorAll('.back-to-hub').forEach(button=>button.onclick=enterHub);
$('#backToHubFromDungeon').onclick=enterHub;
$('#backToDungeon').onclick=()=>{renderDungeonSelection();show('dungeonScreen')};
$('#openArchiveHub').onclick=()=>$('#openMeta').click();
$('#upgradeVault').onclick=upgradeVault;
$('#restart').onclick=enterHub;
$('#confirmRecovery').onclick=()=>finishEndGame(recoverySelected);
const winBattleOpenBase=winBattle;
winBattle=function(){if(!state.openWorld){winBattleOpenBase();return}let map=state.map,node=map.nodes.find(n=>n.id===state.battleNode),enemy=map.enemies.find(e=>e.id===state.battleEnemyId);if(enemy)enemy.alive=false;if(node)node.cleared=true;state.battlesWon++;state.pendingBattle=false;if(state.mapFragment==='blood'&&!state.pendingBoss)state.gold+=8;winBattleOpenBase()}
function validatePackForDeparture(){let d=deckData(),cursed=state.inventory.map((item,i)=>item.templateId==='cursed_blade'?i:-1).filter(i=>i>=0);if(cursed.some(i=>!Object.values(state.placed).some(p=>p.index===i))){message('呪い装備が出発を拒んでいます。必ず配置してください');return null}if(d.cards.length<4){message('基本職業カードを読み込めませんでした');return null}let cells=Object.entries(state.placed).flatMap(([a,p])=>itemCells(a,p));if(new Set(cells.map(c=>`${c.x},${c.y}`)).size===24)unlock('perfect_weight');if(cells.some(c=>c.x===0)&&cells.some(c=>c.x===5)&&cells.some(c=>c.y===0)&&cells.some(c=>c.y===3))unlock('edge_master');checkRoleUnlocks();return d}
$('#startBattle').onclick=()=>{let d=validatePackForDeparture();if(!d)return;if(state.organizing){finishOrganize(d.cards);return}if(state.openWorld&&!state.pendingBattle){state.map.mapStarted=true;showMap();return}startBattle(d.cards)};
$('#scoutMap').onclick=()=>{if(!state.map||state.map.scoutedFrom.includes(state.map.current))return;state.map.scoutedFrom.push(state.map.current);if(state.openWorld)revealOpenArea(state.map.current,jobLevel('scout')>=3?3:2);showMap();toast(jobLevel('scout')>=1?'斥候の経験で周辺情報を詳しく把握した':'時間をかけて周辺を偵察した')};
$('#extractDungeon').onclick=()=>{if(!state.openWorld||state.map.current!==state.map.entrance)return;let dungeon=currentDungeon(),safe=safeProtectedUids(),mandatory=state.inventory.filter(item=>item.origin==='heirloom'||item.origin==='vault'||safe.has(item.uid));pendingEnd={win:true,dungeon,unlocked:false,recovered:state.gold,mandatory};finishEndGame([]);$('#endTitle').textContent=`${dungeon.name}から帰還`;$('#endText').textContent=`探索を切り上げ、${state.gold}Gと保護・持込装備を持ち帰った。戦闘勝利 ${state.battlesWon}回、警戒段階 ${alertStage()}。`};
enterHub();
